#include "surface_ops.h"
__declspec(dllexport) void run(void) { H text_h,x_h,y_h,color; cvm_pop(color); cvm_pop(y_h); cvm_pop(x_h); cvm_pop(text_h); HWND w=surface_hwnd(); u32 len=0; u8*d=block_read(text_h,&len); if(w&&d){HDC dc=GetDC(w); SetTextColor(dc,(COLORREF)cvm_h_to_u64(color)); SetBkMode(dc,TRANSPARENT); TextOutA(dc,(int)cvm_h_to_u64(x_h),(int)cvm_h_to_u64(y_h),(char*)d,(int)len); ReleaseDC(w,dc);} if(d)free(d); cnext(); }
